let myChartInstance=null;let allocationChartInstance=null;let marketChartInstance=null;let chartModal=null;let sellModal=null;let currentBondIsin=null;let currentBondLabels=[];let currentBondPrices=[];let currentBondNkd=[];let currentBondYtm=[];let historyLoaded=false;let incomeData={};let currentPreviewPrice=null;let bondsData=[];let sortKey=null;let sortDir=1;function getCurrencySymbol(cur){switch(cur){case 'USD':return '$';case 'CNY':return '¥';case 'EUR':return '€';case 'GLD':return 'г';case 'RUB':default:return '₽';}}document.getElementById('bondDate').value=new Date().toISOString().split('T')[0];document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(el=>{new bootstrap.Tooltip(el);});});async function openBondChart(isin){currentBondIsin=isin;document.getElementById('chartModalIsinTitle').innerText=isin;if(!chartModal)chartModal=new bootstrap.Modal(document.getElementById('bondChartModal'));chartModal.show();await loadBondChartData('month');const buttons=document.querySelectorAll('#periodBtnGroup .btn');buttons.forEach(btn=>btn.classList.remove('active'));const defaultBtn=document.querySelector('#periodBtnGroup[data-period="month"]');if(defaultBtn)defaultBtn.classList.add('active');}async function loadBondChartData(period){if(!currentBondIsin)return;const response=await fetch(`/api/bond_chart/${currentBondIsin}?range=${period}`);if(!response.ok)return;const resData=await response.json();currentBondLabels=resData.labels ||[];currentBondPrices=resData.data ||[];currentBondNkd=resData.nkd ||[];currentBondYtm=resData.ytm ||[];const ctx=document.getElementById('marketBondChart').getContext('2d');if(marketChartInstance)marketChartInstance.destroy();marketChartInstance=new Chart(ctx,{type:'line',data:{labels:currentBondLabels,datasets:[{label:'Рыночная стоимость(₽)',data:currentBondPrices,borderColor:'#0d6efd',backgroundColor:'rgba(13,110,253,0.04)',borderWidth:2,fill:true,pointRadius:period==='all' ? 0:(period==='day' || period==='week' ? 5:2)}]},options:{responsive:true,maintainAspectRatio:false,plugins:{tooltip:{callbacks:{label:ctx=>`Цена бумаги:${ctx.parsed.y}₽`,footer:items=>{const i=items[0].dataIndex;return `НКД на дату:${currentBondNkd[i]}₽\nДоходность YTM:${currentBondYtm[i]}%`;}}},zoom:{pan:{enabled:true,mode:'x'},zoom:{wheel:{enabled:true},pinch:{enabled:true},mode:'x'}}}}});}function applyChartScale(period,ev){if(ev && ev.target && ev.target.classList.contains('btn')){document.querySelectorAll('#periodBtnGroup .btn').forEach(b=>b.classList.remove('active'));ev.target.classList.add('active');}loadBondChartData(period);}async function loadDashboard(){await fetchActivePortfolio();fetchChartAnalytics();fetchCouponCalendar();fetchIncomeWidget();}async function fetchCouponCalendar(){const response=await fetch('/api/portfolio/calendar');if(!response.ok)return;const events=await response.json();const list=document.getElementById('coupon-calendar-list');list.innerHTML='';if(events.length===0){list.innerHTML='<li class="list-group-item text-center text-muted py-3">Нет предстоящих купонов.</li>';return;}const esc=window.Common.escapeHtml;events.forEach(e=>{list.innerHTML+=`<li class="list-group-item d-flex justify-content-between align-items-center"><div><b>${esc(e.name)}</b><br><small class="text-muted">${esc(e.date)}</small></div><span class="badge bg-success font-monospace">+${parseFloat(e.total_payout).toFixed(2)}₽</span></li>`;});}function sortTable(key){if(sortKey===key)sortDir=-sortDir;else{sortKey=key;sortDir=1;}renderBondRows();_updateSortIndicators();}function _updateSortIndicators(){document.querySelectorAll('.sort-icon').forEach(el=>{const col=el.dataset.col;el.textContent=col===sortKey ?(sortDir===1 ? ' ↑':' ↓'):'';});}function _skeletonRows(cols=9,rows=4){let html='';const widths=['60%','30%','20%','25%','20%','20%','20%','30%','15%'];for(let r=0;r<rows;r++){html+='<tr>';for(let c=0;c<cols;c++){const w=widths[c]|| '30%';html+=`<td><span class="skeleton-cell" style="width:${w}"></span></td>`;}html+='</tr>';}return html;}async function fetchActivePortfolio(){const tbody=document.getElementById('bonds-table-body');tbody.innerHTML=_skeletonRows();const response=await fetch('/api/portfolio');if(response.status===401){window.location.href='/';return;}const data=await response.json();document.getElementById('total-portfolio-value').innerText=data.total_value.toLocaleString('ru-RU',{minimumFractionDigits:2});const ytmEl=document.getElementById('portfolio-ytm');if(ytmEl)ytmEl.textContent=data.portfolio_ytm ? data.portfolio_ytm.toFixed(2)+' %':'—';const countEl=document.getElementById('portfolio-count');if(countEl)countEl.textContent=(data.bonds ||[]).length;bondsData=data.bonds ||[];renderBondRows();renderAllocationChart();}function renderBondRows(){const tbody=document.getElementById('bonds-table-body');tbody.innerHTML='';if(!bondsData.length){tbody.innerHTML=`<tr><td colspan="9" class="text-center text-muted py-5"><div style="font-size:2.5rem;opacity:.2;line-height:1">📊</div><div class="fw-semibold mt-2 mb-1">Портфель пуст</div><small class="text-secondary">Найдите облигацию по ISIN или названию и добавьте первую позицию.</small></td></tr>`;return;}const grouped={};bondsData.forEach(bond=>{if(!grouped[bond.isin]){grouped[bond.isin]={isin:bond.isin,name:bond.name,currency:bond.currency || 'RUB',lots:[],total_amount:0,total_cost:0,total_pnl:0,nkd:bond.nkd || 0,ytm:bond.ytm || 0,last_price:bond.last_price || bond.buy_price};}const g=grouped[bond.isin];g.lots.push(bond);g.total_amount+=bond.amount;g.total_cost+=bond.buy_price * bond.amount;g.total_pnl+=bond.pnl || 0;});let sorted=Object.values(grouped);if(sortKey){sorted.sort((a,b)=>{let key=sortKey;let va=a[key];let vb=b[key];if(key==='amount'){va=a.total_amount;vb=b.total_amount;}else if(key==='buy_price'){va=a.total_amount ?(a.total_cost / a.total_amount):0;vb=b.total_amount ?(b.total_cost / b.total_amount):0;}else if(key==='pnl'){va=a.total_pnl;vb=b.total_pnl;}if(typeof va==='string'){va=va.toLowerCase();vb=(vb || '').toLowerCase();}return(va<vb ?-1:va>vb ? 1:0)* sortDir;});}const esc=window.Common.escapeHtml;function getLotLabel(count){if(count % 10===1 && count % 100 !==11){return `${count}лот`;}else if([2,3,4].includes(count % 10)&& ![12,13,14].includes(count % 100)){return `${count}лота`;}else{return `${count}лотов`;}}sorted.forEach(g=>{const avgBuyPrice=g.total_amount ?(g.total_cost / g.total_amount):0;const pnlPct=g.total_cost ?(g.total_pnl / g.total_cost * 100):0;const pnlClass=g.total_pnl>=0 ? 'text-success':'text-danger';const sign=g.total_pnl>=0 ? '+':'';const sym=getCurrencySymbol(g.currency || 'RUB');tbody.innerHTML+=`<tr class="summary-row" data-name="${esc(g.name)}" data-isin="${esc(g.isin)}"><td data-label="Название"><b>${esc(g.name)}</b></td><td data-label="ISIN"><b class="isin-link" onclick="openBondChart(this.dataset.isin)" data-isin="${esc(g.isin)}">${esc(g.isin)}</b></td><td data-label="Кол-во">${g.total_amount}шт.</td><td data-label="Цена покупки">${avgBuyPrice.toFixed(2)}${sym}</td><td data-label="Текущая цена">${g.last_price.toFixed(2)}${sym}</td><td data-label="НКД" class="text-primary"><b>${g.nkd.toFixed(2)}${sym}</b></td><td data-label="YTM" class="text-info"><b>${g.ytm.toFixed(2)}%</b></td><td data-label="P&L" class="${pnlClass}"><b>${sign}${g.total_pnl.toFixed(2)}₽</b><br><small>${sign}${pnlPct.toFixed(2)}%</small></td><td><button class="btn btn-xs btn-outline-info toggle-lots-btn" data-isin="${esc(g.isin)}" onclick="toggleLots('${esc(g.isin)}')">${getLotLabel(g.lots.length)}▾</button></td></tr><tr class="lots-row d-none" id="lots-${esc(g.isin)}"><td colspan="9" class="p-3 bg-light-subtle"><div class="card card-body shadow-sm py-2 px-3 border border-subtle"><table class="table table-sm table-borderless mb-0 align-middle" style="font-size:0.8rem;"><thead><tr class="text-secondary border-bottom border-subtle" style="font-size:0.72rem;"><th>Дата покупки</th><th>Кол-во</th><th>Цена покупки</th><th>Текущая цена</th><th>P&L</th><th>Заметка</th><th class="text-end">Действия</th></tr></thead><tbody>${g.lots.map(lot=>{const lotPnl=lot.pnl ?? 0;const lotPnlPct=lot.pnl_pct ?? 0;const lotPnlClass=lotPnl>=0 ? 'text-success':'text-danger';const lotSign=lotPnl>=0 ? '+':'';const lotSym=getCurrencySymbol(lot.currency || 'RUB');return `<tr style="border-bottom:1px solid rgba(var(--accent-rgb),0.05);"><td>${esc(lot.purchase_date || '—')}</td><td>${lot.amount}шт.</td><td>${lot.buy_price.toFixed(2)}${lotSym}</td><td>${(lot.last_price || lot.buy_price).toFixed(2)}${lotSym}</td><td class="${lotPnlClass}"><b>${lotSign}${lotPnl.toFixed(2)}₽</b>(${lotSign}${lotPnlPct.toFixed(2)}%)</td><td><span class="text-truncate d-inline-block" style="max-width:120px;" title="${esc(lot.notes || '')}">${esc(lot.notes || '—')}</span></td><td class="text-end"><button onclick="sellTrigger(${lot.id},'${esc(lot.name)}',${lot.last_price || lot.buy_price},${lot.buy_price},${lot.amount})" class="btn btn-xs btn-outline-success py-0 px-2">Продать</button><button data-note-btn="${lot.id}" title="${esc(lot.notes || 'Добавить заметку')}" onclick="openNotesModal(${lot.id},${JSON.stringify(lot.notes || '')})" class="btn btn-xs btn-outline-secondary ms-1 py-0 px-2 ${lot.notes ? 'note-filled':''}">📝</button></td></tr>`;}).join('')}</tbody></table></div></td></tr>`;});}window.toggleLots=function(isin){const row=document.getElementById(`lots-${isin}`);const btn=document.querySelector(`.toggle-lots-btn[data-isin="${isin}"]`);if(!row || !btn)return;if(row.classList.contains('d-none')){row.classList.remove('d-none');btn.innerHTML=btn.innerHTML.replace('▾','▴');}else{row.classList.add('d-none');btn.innerHTML=btn.innerHTML.replace('▴','▾');}};let notesModal=null;window.openNotesModal=function(bondId,currentNotes){document.getElementById('modalNoteText').value=currentNotes || '';const saveBtn=document.getElementById('saveModalNoteBtn');const newSaveBtn=saveBtn.cloneNode(true);saveBtn.parentNode.replaceChild(newSaveBtn,saveBtn);newSaveBtn.addEventListener('click',async()=>{const notes=document.getElementById('modalNoteText').value;newSaveBtn.disabled=true;newSaveBtn.textContent='Сохранение...';try{const res=await window.Common.csrfFetch(`/api/portfolio/${bondId}/notes`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({notes}),});const data=await res.json();if(res.ok){window.Common.showToast('Заметка сохранена');await fetchActivePortfolio();if(notesModal)notesModal.hide();}else{window.Common.showSystemMessage(data.message || 'Ошибка',true);}}finally{newSaveBtn.disabled=false;newSaveBtn.textContent='Сохранить';}});if(!notesModal){notesModal=new bootstrap.Modal(document.getElementById('notesModal'));}notesModal.show();};let currentTxType='';window.setHistoryTxType=function(txType,btn){currentTxType=txType;document.querySelectorAll('#historyTxTypeGroup .btn').forEach(b=>b.classList.remove('active'));if(btn)btn.classList.add('active');fetchTradeHistory();};function loadHistoryIfNeeded(){if(!historyLoaded){fetchTradeHistory();historyLoaded=true;}}async function fetchTradeHistory(dateFrom='',dateTo=''){const loading=document.getElementById('history-loading');const tbody=document.getElementById('history-table-body');if(loading)loading.style.display='block';tbody.innerHTML=_skeletonRows(9,3);try{const params=new URLSearchParams();if(dateFrom)params.set('date_from',dateFrom);if(dateTo)params.set('date_to',dateTo);params.set('tx_type',currentTxType);const url='/api/portfolio/history'+(params.toString()? '?'+params.toString():'');const response=await fetch(url);if(!response.ok)return;const data=await response.json();tbody.innerHTML='';if(!data.trades || data.trades.length===0){tbody.innerHTML=`<tr><td colspan="9" class="text-center text-muted py-4">${dateFrom || dateTo ? 'Нет сделок за выбранный период.':'История сделок пуста.'}</td></tr>`;return;}const esc=window.Common.escapeHtml;data.trades.forEach(t=>{const pnlClass=t.tx_type==='sell' ?(t.pnl>=0 ? 'text-success':'text-danger'):'text-secondary';const sign=t.pnl>=0 ? '+':'';const typeBadge=t.tx_type==='buy' ? '<span class="badge bg-primary-subtle text-primary border border-primary-subtle" style="font-size:0.7rem">Покупка</span>':'<span class="badge bg-warning-subtle text-warning border border-warning-subtle" style="font-size:0.7rem">Продажа</span>';const pnlStr=t.tx_type==='sell' ? `<b>${sign}${t.pnl.toFixed(2)}₽</b>`:'—';const pnlPctStr=t.tx_type==='sell' ? `<b>${sign}${t.pnl_pct.toFixed(2)}%</b>`:'—';const dateStr=t.tx_type==='sell' ? esc(t.sell_date || '—'):esc(t.purchase_date || '—');const sellPriceStr=t.tx_type==='sell' ? `${t.sell_price.toFixed(2)}₽`:'—';tbody.innerHTML+=`<tr><td><b>${esc(t.name)}</b></td><td><small class="text-muted">${esc(t.isin)}</small></td><td>${typeBadge}</td><td>${t.amount}шт.</td><td>${t.buy_price.toFixed(2)}₽</td><td>${sellPriceStr}</td><td class="${pnlClass}">${pnlStr}</td><td class="${pnlClass}">${pnlPctStr}</td><td><small>${dateStr}</small></td></tr>`;});}finally{if(loading)loading.style.display='none';}}function applyHistoryFilter(){const from=document.getElementById('historyDateFrom').value;const to=document.getElementById('historyDateTo').value;fetchTradeHistory(from,to);}function clearHistoryFilter(){document.getElementById('historyDateFrom').value='';document.getElementById('historyDateTo').value='';fetchTradeHistory();}async function fetchBondPreview(isin){if(!isin || isin.length<2)return;try{const res=await fetch(`/api/bond_preview/${encodeURIComponent(isin)}`);if(!res.ok){hideBondPreview();return;}const d=await res.json();if(d.status !=='ok'){hideBondPreview();return;}const cur=d.currency || 'RUB';const sym=getCurrencySymbol(cur);document.getElementById('previewName').textContent=d.name || isin;document.getElementById('previewPrice').textContent=d.price !=null ? d.price.toFixed(2)+' '+sym:'—';document.getElementById('previewYtm').textContent=d.ytm !=null ? d.ytm.toFixed(2)+' %':'—';document.getElementById('previewMatdate').textContent=d.matdate || '—';document.getElementById('previewNkd').textContent=d.nkd !=null ? d.nkd.toFixed(2)+' '+sym:'—';const labelEl=document.getElementById('buyPriceCurrencyLabel');if(labelEl)labelEl.textContent=sym;let couponText='—';if(d.coupon_pct !=null){couponText=d.coupon_pct+'%';if(d.coupon_freq)couponText+=` × ${d.coupon_freq}/год`;}document.getElementById('previewCoupon').textContent=couponText;document.getElementById('bondPreview').style.display='block';currentPreviewPrice=d.price !=null ? d.price:null;const checkbox=document.getElementById('bondUseMarketPrice');const priceField=document.getElementById('bondBuyPrice');if(checkbox && checkbox.checked && currentPreviewPrice !=null){priceField.value=currentPreviewPrice.toFixed(2);priceField.dataset.autofilled='true';}else if(!priceField.value || priceField.dataset.autofilled==='true'){if(currentPreviewPrice !=null){priceField.value=currentPreviewPrice.toFixed(2);priceField.dataset.autofilled='true';}}}catch(_){hideBondPreview();}}function hideBondPreview(){document.getElementById('bondPreview').style.display='none';currentPreviewPrice=null;const labelEl=document.getElementById('buyPriceCurrencyLabel');if(labelEl)labelEl.textContent='₽';}(function setupMarketPriceCheckbox(){const checkbox=document.getElementById('bondUseMarketPrice');const priceField=document.getElementById('bondBuyPrice');if(!checkbox || !priceField)return;checkbox.addEventListener('change',()=>{if(checkbox.checked && currentPreviewPrice !=null){priceField.value=currentPreviewPrice.toFixed(2);priceField.dataset.autofilled='true';priceField.readOnly=true;}else{priceField.readOnly=false;}});priceField.addEventListener('input',()=>{if(checkbox.checked){checkbox.checked=false;priceField.readOnly=false;}priceField.dataset.autofilled='';});})();document.getElementById('addBondForm').addEventListener('submit',async(e)=>{e.preventDefault();const btn=document.getElementById('addBondBtn');btn.disabled=true;btn.textContent='Загрузка…';const isin=document.getElementById('bondIsin').value.trim();const amount=document.getElementById('bondAmount').value;const buy_price=document.getElementById('bondBuyPrice').value;const purchase_date=document.getElementById('bondDate').value;const notes=document.getElementById('bondNotes')?.value || '';try{const response=await window.Common.csrfFetch('/api/add_bond',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({isin,amount,buy_price,purchase_date,notes})});const data=await response.json();if(response.ok && data.status==='success'){if(data.duplicate_warning){window.Common.showToast(`${data.message}Внимание:в портфеле уже есть ${data.existing_amount}шт. этой бумаги.`,false,true);}else{window.Common.showToast(data.message);}document.getElementById('addBondForm').reset();document.getElementById('bondDate').value=new Date().toISOString().split('T')[0];historyLoaded=false;await loadDashboard();}else{window.Common.showSystemMessage(data.message,true);}}finally{btn.disabled=false;btn.textContent='Добавить в портфель';}});async function fetchChartAnalytics(){const response=await fetch('/api/portfolio_stats');if(!response.ok)return;const chartData=await response.json();const ctx=document.getElementById('profitChart').getContext('2d');if(myChartInstance)myChartInstance.destroy();myChartInstance=new Chart(ctx,{type:'bar',data:chartData,options:{responsive:true,maintainAspectRatio:false}});}(function setupBondSearch(){const isinInput=document.getElementById('bondIsin');const dropdown=document.getElementById('isinDropdown');let debounceTimer=null;isinInput.addEventListener('input',()=>{clearTimeout(debounceTimer);const q=isinInput.value.trim();if(q.length<2){dropdown.style.display='none';return;}debounceTimer=setTimeout(async()=>{try{const res=await fetch(`/api/search_bond?q=${encodeURIComponent(q)}`);if(!res.ok)return;renderDropdown(await res.json());}catch(_){}},300);});function renderDropdown(results){dropdown.innerHTML='';if(!results || !results.length){dropdown.style.display='none';return;}const esc=window.Common.escapeHtml;results.forEach(item=>{const div=document.createElement('div');div.className='isin-dropdown-item';div.innerHTML=`<span class="fw-semibold">${esc(item.isin)}</span><span class="text-muted ms-2 small">${esc(item.name)}</span>`;div.addEventListener('mousedown',e=>{e.preventDefault();isinInput.value=item.isin;dropdown.style.display='none';fetchBondPreview(item.isin);});dropdown.appendChild(div);});dropdown.style.display='block';}document.addEventListener('click',e=>{if(!isinInput.contains(e.target)&& !dropdown.contains(e.target))dropdown.style.display='none';});isinInput.addEventListener('keydown',e=>{if(e.key==='Escape')dropdown.style.display='none';});isinInput.addEventListener('blur',()=>{const val=isinInput.value.trim();if(val.length>=10)fetchBondPreview(val);});isinInput.addEventListener('input',()=>{if(!isinInput.value.trim())hideBondPreview();document.getElementById('bondBuyPrice').dataset.autofilled='';});})();function renderAllocationChart(){const canvas=document.getElementById('allocationChart');const emptyEl=document.getElementById('allocationEmpty');if(!canvas)return;if(!bondsData.length){if(emptyEl)emptyEl.style.display='block';if(allocationChartInstance){allocationChartInstance.destroy();allocationChartInstance=null;}return;}if(emptyEl)emptyEl.style.display='none';const labels=bondsData.map(b=>b.name);const values=bondsData.map(b=>b.current_value);const colors=bondsData.map((_,i)=>`hsl(${Math.round((i * 137.5)% 360)},60%,55%)`);if(allocationChartInstance)allocationChartInstance.destroy();allocationChartInstance=new Chart(canvas.getContext('2d'),{type:'doughnut',data:{labels,datasets:[{data:values,backgroundColor:colors,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'right',labels:{font:{size:10},boxWidth:12}},tooltip:{callbacks:{label:ctx=>{const total=ctx.dataset.data.reduce((s,v)=>s+v,0);const pct=total ?((ctx.parsed / total)* 100).toFixed(1):0;return ` ${ctx.parsed.toLocaleString('ru-RU',{maximumFractionDigits:0})}₽(${pct}%)`;}}}}}});}async function fetchIncomeWidget(){try{const res=await fetch('/api/portfolio/income');if(!res.ok)return;incomeData=await res.json();showIncome('30d');}catch(_){}}function showIncome(period,btn){if(btn){document.querySelectorAll('#incomeGroup .btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}const val=incomeData[period];const el=document.getElementById('incomeValue');const hint=document.getElementById('incomeHint');if(el)el.textContent=val !=null ? val.toLocaleString('ru-RU',{minimumFractionDigits:2})+' ₽':'—';const labels={'30d':'следующие 30 дней','90d':'следующие 90 дней','365d':'следующий год'};if(hint)hint.textContent='купоны за '+(labels[period]|| period);}function sellTrigger(bondId,name,sellPrice,buyPrice,amount){const nameEl=document.getElementById('sellModalBondName');const priceEl=document.getElementById('sellPriceInput');const commEl=document.getElementById('sellCommissionInput');const amountEl=document.getElementById('sellAmountInput');const hintEl=document.getElementById('sellMaxAmountHint');if(nameEl)nameEl.textContent=name;if(priceEl)priceEl.value=sellPrice.toFixed(2);if(commEl)commEl.value='';if(amountEl){amountEl.value=amount;amountEl.max=amount;amountEl.min=1;}if(hintEl)hintEl.textContent=`Доступно:${amount}шт.`;function updatePnlPreview(){const sp=parseFloat(priceEl?.value)|| 0;const comm=parseFloat(commEl?.value)|| 0;const qty=parseFloat(amountEl?.value)|| amount || 1;const pnl=(sp-(buyPrice || sp))* qty-comm;const pct=buyPrice ?((sp-buyPrice)/ buyPrice * 100):0;const el=document.getElementById('sellPnlPreview');if(!el)return;const sign=pnl>=0 ? '+':'';el.textContent=`${sign}${pnl.toLocaleString('ru-RU',{minimumFractionDigits:2,maximumFractionDigits:2})}₽(${sign}${pct.toFixed(2)}%)`;el.style.color=pnl>=0 ? 'var(--text-success)':'var(--text-danger)';}priceEl?.addEventListener('input',updatePnlPreview);commEl?.addEventListener('input',updatePnlPreview);amountEl?.addEventListener('input',updatePnlPreview);updatePnlPreview();if(!sellModal)sellModal=new bootstrap.Modal(document.getElementById('sellModal'));const btn=document.getElementById('sellModalConfirmBtn');const newBtn=btn.cloneNode(true);btn.parentNode.replaceChild(newBtn,btn);newBtn.addEventListener('click',async()=>{const price=parseFloat(document.getElementById('sellPriceInput').value);const comm=parseFloat(document.getElementById('sellCommissionInput').value)|| 0;const qty=parseInt(document.getElementById('sellAmountInput').value,10);if(isNaN(price)|| price<=0)return;if(isNaN(qty)|| qty<=0 || qty>amount){window.Common.showToast(`Укажите количество от 1 до ${amount}шт.`,true);return;}sellModal.hide();const response=await window.Common.csrfFetch(`/api/sell_bond/${bondId}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sell_price:price,broker_commission:comm || null,amount:qty})});const data=await response.json();if(response.ok){window.Common.showToast(data.message);historyLoaded=false;await loadDashboard();}else{window.Common.showSystemMessage(data.message,true);}});sellModal.show();}let watchlistLoaded=false;function loadWatchlistIfNeeded(){if(!watchlistLoaded)fetchWatchlist();}async function fetchWatchlist(){const tbody=document.getElementById('watchlist-table-body');tbody.innerHTML=_skeletonRows(7,3);const res=await window.Common.csrfFetch('/api/watchlist');if(!res.ok){tbody.innerHTML='<tr><td colspan="7" class="text-center text-danger py-3">Ошибка загрузки</td></tr>';return;}const items=await res.json();watchlistLoaded=true;const esc=window.Common.escapeHtml;if(!items.length){tbody.innerHTML=`<tr><td colspan="7" class="text-center text-muted py-4">⭐ Список пуст. Добавьте облигации через кнопку «+Добавить».</td></tr>`;return;}tbody.innerHTML=items.map(item=>{const price=item.price !=null ? item.price.toFixed(2)+' ₽':'—';const ytm=item.ytm !=null ? item.ytm.toFixed(2)+' %':'—';const nkd=item.nkd !=null ? item.nkd.toFixed(2)+' ₽':'—';return `<tr><td>${esc(item.name)}</td><td><span class="isin-link" onclick="openBondChart('${esc(item.isin)}')">${esc(item.isin)}</span></td><td>${price}</td><td>${ytm}</td><td>${nkd}</td><td class="text-muted small">${esc(item.added_at)}</td><td><button class="btn btn-sm btn-outline-danger" onclick="removeFromWatchlist('${esc(item.isin)}')">✕</button></td></tr>`;}).join('');}async function promptAddWatchlist(){const isin=prompt('Введите ISIN облигации:');if(!isin)return;const res=await window.Common.csrfFetch('/api/watchlist',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({isin:isin.trim().toUpperCase()}),});const data=await res.json();if(res.ok){window.Common.showToast(data.message);watchlistLoaded=false;fetchWatchlist();}else{window.Common.showSystemMessage(data.message,true);}}async function removeFromWatchlist(isin){window.Common.askConfirmation(`Удалить ${isin}из избранного?`,async()=>{const res=await window.Common.csrfFetch(`/api/watchlist/${isin}`,{method:'DELETE'});const data=await res.json();window.Common.showToast(data.message,!res.ok);watchlistLoaded=false;fetchWatchlist();});}async function runScreener(){const tbody=document.getElementById('screener-table-body');const loading=document.getElementById('screener-loading');loading.style.display='block';tbody.innerHTML='';const params=new URLSearchParams();const minYtm=document.getElementById('screenerMinYtm')?.value;const maxYtm=document.getElementById('screenerMaxYtm')?.value;const matFrom=document.getElementById('screenerMatFrom')?.value;const matTo=document.getElementById('screenerMatTo')?.value;const issType=document.getElementById('screenerIssuerType')?.value;const minDur=document.getElementById('screenerMinDuration')?.value;const maxDur=document.getElementById('screenerMaxDuration')?.value;if(minYtm)params.set('min_ytm',minYtm);if(maxYtm)params.set('max_ytm',maxYtm);if(matFrom)params.set('maturity_from',matFrom);if(matTo)params.set('maturity_to',matTo);if(issType)params.set('issuer_type',issType);if(minDur)params.set('min_duration',minDur);if(maxDur)params.set('max_duration',maxDur);const res=await window.Common.csrfFetch('/api/screener?'+params.toString());loading.style.display='none';if(!res.ok){tbody.innerHTML='<tr><td colspan="6" class="text-danger text-center py-3">Ошибка загрузки</td></tr>';return;}const results=await res.json();const esc=window.Common.escapeHtml;if(!results.length){tbody.innerHTML='<tr><td colspan="6" class="text-center text-muted py-4">Ничего не найдено по заданным фильтрам.</td></tr>';return;}tbody.innerHTML=results.map(b=>{const ytm=b.ytm !=null ? b.ytm.toFixed(2)+' %':'—';const coupon=b.coupon !=null ? b.coupon+' ₽':'—';const mat=b.matdate || '—';return `<tr><td>${esc(b.name || b.secid)}</td><td><span class="isin-link" onclick="openBondChart('${esc(b.isin)}')">${esc(b.isin)}</span></td><td>${ytm}</td><td>${esc(mat)}</td><td>${coupon}</td><td><button class="btn btn-sm btn-outline-success" title="Добавить в избранное" onclick="addScreenerToWatchlist('${esc(b.isin)}')">⭐</button></td></tr>`;}).join('');}function clearScreener(){['screenerMinYtm','screenerMaxYtm','screenerMatFrom','screenerMatTo','screenerIssuerType','screenerMinDuration','screenerMaxDuration'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});const tbody=document.getElementById('screener-table-body');tbody.innerHTML='<tr><td colspan="6" class="text-center text-muted py-4">Задайте фильтры и нажмите «Найти».</td></tr>';}async function addScreenerToWatchlist(isin){const res=await window.Common.csrfFetch('/api/watchlist',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({isin}),});const data=await res.json();window.Common.showToast(data.message,!res.ok && res.status !==409);if(res.ok){watchlistLoaded=false;}}(function setupImportForm(){const form=document.getElementById('importBrokerForm');if(!form)return;const brokerHints={tinkoff:'Отчёт по сделкам из личного кабинета Т‑Инвестиций(.xlsx)',vtb:'Брокерский отчёт ВТБ(.xlsx)— раздел «Заключённые сделки»',auto:'Универсальный парсер — для других брокеров с похожим форматом',};document.querySelectorAll('.broker-chip').forEach(chip=>{chip.addEventListener('click',()=>{document.querySelectorAll('.broker-chip').forEach(c=>c.classList.remove('active'));chip.classList.add('active');chip.querySelector('input[type=radio]').checked=true;const hintEl=document.getElementById('brokerHint');if(hintEl)hintEl.textContent=brokerHints[chip.dataset.value]|| '';});});form.addEventListener('submit',async(e)=>{e.preventDefault();const fileInput=document.getElementById('importFile');const submitBtn=document.getElementById('importSubmitBtn');const resultDiv=document.getElementById('importResult');const successAlert=document.getElementById('importSuccessAlert');const successTitle=document.getElementById('importSuccessTitle');const successMsg=document.getElementById('importSuccessMsg');const errorAlert=document.getElementById('importErrorAlert');const errorList=document.getElementById('importErrorList');if(!fileInput.files.length)return;submitBtn.disabled=true;submitBtn.textContent='Импорт…';resultDiv.style.display='none';successAlert.style.display='none';errorAlert.style.display='none';const brokerRadio=form.querySelector('input[name="broker"]:checked');const brokerValue=brokerRadio ? brokerRadio.value:'auto';const formData=new FormData();formData.append('file',fileInput.files[0]);formData.append('broker',brokerValue);try{const csrfToken=(()=>{const raw=document.cookie.split(';').find(c=>c.trim().startsWith('XSRF-TOKEN='));if(!raw)return null;try{return decodeURIComponent(raw.split('=')[1]);}catch{return raw.split('=')[1];}})();const headers={};if(csrfToken){headers['X-CSRFToken']=csrfToken;headers['X-CSRF-Token']=csrfToken;}const res=await fetch('/api/portfolio/import',{method:'POST',headers,credentials:'same-origin',body:formData,});const data=await res.json();resultDiv.style.display='block';if(res.ok){successAlert.style.display='';successTitle.textContent='Успешно!';successMsg.textContent=data.message || `Импортировано ${data.imported_count ?? 0}сделок.`;const skipped=data.errors ||[];if(skipped.length){errorAlert.style.display='';errorList.innerHTML=skipped.map(s=>`<li>${window.Common.escapeHtml(s)}</li>`).join('');}else{errorAlert.style.display='none';}}else{successAlert.style.display='none';errorAlert.style.display='';const errors=data.errors ||(data.message ?[data.message]:['Неизвестная ошибка']);errorList.innerHTML=errors.map(s=>`<li>${window.Common.escapeHtml(String(s))}</li>`).join('');}}catch(err){resultDiv.style.display='block';successAlert.style.display='none';errorAlert.style.display='';errorList.innerHTML=`<li>${window.Common.escapeHtml(String(err))}</li>`;}finally{submitBtn.disabled=false;submitBtn.textContent='Загрузить и импортировать';historyLoaded=false;loadDashboard().catch(()=>{});}});})();loadDashboard();